(function(){"use strict";class r{constructor(e){this.el=e}init(){this.observer=new IntersectionObserver(e=>{e.forEach(i=>{i.isIntersecting?this.el.play():this.el.pause()})},{threshold:.1}),this.observer.observe(this.el)}}function t(){document.querySelectorAll("[data-observer-autoplay]").forEach(s=>{new r(s).init()})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",t):t()})();
